#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    long long candy(vector<int>& ratings) {
        int n = ratings.size();
        vector<int> candies(n, 1);
        for (int i = 1; i < n; i++) {
            if (ratings[i] > ratings[i - 1]) {
                candies[i] = candies[i - 1] + 1;
            }
        }
        for (int i = n - 2; i >= 0; i--) {
            if (ratings[i] > ratings[i + 1] && candies[i] <= candies[i + 1]) {
                candies[i] = candies[i + 1] + 1;
            }
        }
        long long sum = 0;
        for (int candy : candies) {
            sum += candy;
        }
        return sum;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> ratings(n);
    for (int i = 0; i < n; i++) cin >> ratings[i];
    Solution sol;
    long long ans = sol.candy(ratings);
    cout << ans << "\n";
    return 0;
}
